1	// Package libvirt implements the local VM provider backed by libvirt/KVM. All
2	// hypervisor interaction shells out to virsh, virt-install, and qemu-img via an
3	// explicit-argument Runner (no shell), so VM names and paths cannot inject
4	// commands.
5	package libvirt
6	
7	import (
8		"context"
9		"fmt"
10		"io"
11		"os"
12		"os/exec"
13		"path/filepath"
14		"strconv"
15		"strings"
16		"syscall"
17		"time"
18	
19		"github.com/gherlein/govirt/internal/cloudinit"
20		"github.com/gherlein/govirt/internal/config"
21		"github.com/gherlein/govirt/internal/provider"
22	)
23	
24	// DefaultPoolDir is the libvirt default storage pool directory.
25	const DefaultPoolDir = "/var/lib/libvirt/images"
26	
27	// DefaultNetwork is the libvirt network VMs attach to.
28	const DefaultNetwork = "default"
29	
30	// ImageEnsurer resolves an image shorthand to a local cached base image path.
31	// *images.Manager satisfies it.
32	type ImageEnsurer interface {
33		Ensure(ctx context.Context, image string) (string, error)
34	}
35	
36	// Provider is the libvirt VMProvider implementation.
37	type Provider struct {
38		Runner  Runner
39		Images  ImageEnsurer
40		PoolDir string
41		Verbose bool
42		Out     io.Writer
43	}
44	
45	// New returns a Provider with production defaults.
46	func New(images ImageEnsurer) *Provider {
47		return &Provider{
48			Runner:  execRunner{},
49			Images:  images,
50			PoolDir: DefaultPoolDir,
51			Out:     os.Stderr,
52		}
53	}
54	
55	// Name implements provider.VMProvider.
56	func (p *Provider) Name() string { return "local" }
57	
58	func (p *Provider) out() io.Writer {
59		if p.Out != nil {
60			return p.Out
61		}
62		return os.Stderr
63	}
64	
65	func (p *Provider) diskPath(name string) string {
66		return filepath.Join(p.PoolDir, name+".qcow2")
67	}
68	
69	func (p *Provider) isoPath(name string) string {
70		return filepath.Join(p.PoolDir, name+"-cloud-init.iso")
71	}
72	
73	// Create provisions a local VM from the processed cloud-init document at
74	// cloudInitPath.
75	func (p *Provider) Create(ctx context.Context, cfg *config.Config, cloudInitPath string) error {
76		if cfg.VM == nil {
77			return fmt.Errorf("config missing vm section")
78		}
79		name := cfg.VM.Name
80		if err := config.ValidateName(name); err != nil {
81			return err
82		}
83		if err := p.checkPrereqs(); err != nil {
84			return err
85		}
86		if p.exists(ctx, name) {
87			return fmt.Errorf("VM already exists: destroy first with 'govirt destroy %s'", name)
88		}
89	
90		base, err := p.Images.Ensure(ctx, cfg.VM.Image)
91		if err != nil {
92			return err
93		}
94	
95		disk := p.diskPath(name)
96		if err := p.createDisk(ctx, base, disk, cfg.VM.Disk); err != nil {
97			return err
98		}
99	
100		userData, err := os.ReadFile(cloudInitPath)
101		if err != nil {
102			return fmt.Errorf("reading processed cloud-init: %w", err)
103		}
104		iso := p.isoPath(name)
105		tool := detectISOTool()
106		if err := buildISO(ctx, p.Runner, tool, name, string(userData), iso); err != nil {
107			return err
108		}
109	
110		memMB, err := parseMemoryMB(cfg.VM.Memory)
111		if err != nil {
112			return err
113		}
114		variant := mapOSVariant(cfg.VM.Image)
115		args := buildVirtInstallArgs(name, memMB, cfg.VM.CPUs, disk, iso, variant, DefaultNetwork, cfg.VM.Mounts, true)
116		if err := p.Runner.Run(ctx, "virt-install", args...); err != nil {
117			return err
118		}
119	
120		ip := pollIP(ctx, p.Runner, name, DefaultNetwork, defaultIPPoll)
121		if ip == "" {
122			fmt.Fprintf(p.out(), "warning: VM started but no IP assigned after %s: check libvirt network with 'virsh net-list'\n", defaultIPPoll.timeout)
123		}
124	
125		cfg.Local = &config.LocalState{
126			IP:           ip,
127			DomainName:   name,
128			DiskPath:     disk,
129			CloudInitISO: iso,
130			Network:      DefaultNetwork,
131		}
132		return nil
133	}
134	
135	// createDisk builds a copy-on-write overlay over the cached base image and
136	// resizes it to the requested size.
137	func (p *Provider) createDisk(ctx context.Context, base, disk, size string) error {
138		if err := p.Runner.Run(ctx, "qemu-img", "create", "-f", "qcow2",
139			"-b", base, "-F", "qcow2", disk, size); err != nil {
140			return fmt.Errorf("creating VM disk: %w", err)
141		}
142		if err := p.Runner.Run(ctx, "qemu-img", "resize", disk, size); err != nil {
143			return fmt.Errorf("resizing VM disk: %w", err)
144		}
145		return nil
146	}
147	
148	// Delete force-stops and removes the VM, its storage, and the cloud-init ISO.
149	func (p *Provider) Delete(ctx context.Context, cfg *config.Config) error {
150		name := cfg.VM.Name
151		if err := config.ValidateName(name); err != nil {
152			return err
153		}
154		// Ignore error: the domain may already be stopped.
155		_ = p.Runner.Run(ctx, "virsh", "destroy", name)
156		if err := p.Runner.Run(ctx, "virsh", "undefine", name, "--remove-all-storage"); err != nil {
157			return err
158		}
159		if cfg.Local != nil && cfg.Local.CloudInitISO != "" {
160			os.Remove(cfg.Local.CloudInitISO)
161		} else {
162			os.Remove(p.isoPath(name))
163		}
164		cfg.Local = nil
165		return nil
166	}
167	
168	// Stop performs a graceful ACPI shutdown and waits for the domain to stop.
169	func (p *Provider) Stop(ctx context.Context, cfg *config.Config) error {
170		name := cfg.VM.Name
171		if err := config.ValidateName(name); err != nil {
172			return err
173		}
174		if err := p.Runner.Run(ctx, "virsh", "shutdown", name); err != nil {
175			return err
176		}
177		deadline := time.Now().Add(30 * time.Second)
178		for {
179			if p.domState(ctx, name) == "shut off" {
180				return nil
181			}
182			if time.Now().After(deadline) {
183				return fmt.Errorf("VM %s did not stop within 30s", name)
184			}
185			select {
186			case <-ctx.Done():
187				return ctx.Err()
188			case <-time.After(2 * time.Second):
189			}
190		}
191	}
192	
193	// Start boots the VM and refreshes its IP in state.
194	func (p *Provider) Start(ctx context.Context, cfg *config.Config) error {
195		name := cfg.VM.Name
196		if err := config.ValidateName(name); err != nil {
197			return err
198		}
199		if err := p.Runner.Run(ctx, "virsh", "start", name); err != nil {
200			return err
201		}
202		network := DefaultNetwork
203		if cfg.Local != nil && cfg.Local.Network != "" {
204			network = cfg.Local.Network
205		}
206		ip := pollIP(ctx, p.Runner, name, network, defaultIPPoll)
207		if ip != "" {
208			if cfg.Local == nil {
209				cfg.Local = &config.LocalState{Network: network, DomainName: name}
210			}
211			cfg.Local.IP = ip
212		}
213		return nil
214	}
215	
216	// Status reports the VM state and current IP.
217	func (p *Provider) Status(ctx context.Context, cfg *config.Config) (*provider.VMStatus, error) {
218		name := cfg.VM.Name
219		if err := config.ValidateName(name); err != nil {
220			return nil, err
221		}
222		state := p.domState(ctx, name)
223		if state == "" {
224			return nil, fmt.Errorf("VM not found: check 'govirt list' for available VMs")
225		}
226		network := DefaultNetwork
227		if cfg.Local != nil && cfg.Local.Network != "" {
228			network = cfg.Local.Network
229		}
230		ip := ""
231		if state == "running" {
232			ip = lookupIP(ctx, p.Runner, name, network)
233		}
234		return &provider.VMStatus{Name: name, State: state, IP: ip, Provider: p.Name()}, nil
235	}
236	
237	// List returns all libvirt domains.
238	func (p *Provider) List(ctx context.Context) ([]provider.VMStatus, error) {
239		out, err := p.Runner.Output(ctx, "virsh", "list", "--all")
240		if err != nil {
241			return nil, err
242		}
243		var result []provider.VMStatus
244		for _, d := range parseList(string(out)) {
245			st := provider.VMStatus{Name: d.Name, State: d.State, Provider: p.Name()}
246			if d.State == "running" {
247				st.IP = lookupIP(ctx, p.Runner, d.Name, DefaultNetwork)
248			}
249			result = append(result, st)
250		}
251		return result, nil
252	}
253	
254	// SSH replaces the current process with an interactive ssh session to the VM.
255	func (p *Provider) SSH(ctx context.Context, cfg *config.Config) error {
256		name := cfg.VM.Name
257		if err := config.ValidateName(name); err != nil {
258			return err
259		}
260		if len(cfg.VM.Users) == 0 {
261			return fmt.Errorf("no users defined for %s", name)
262		}
263		ip := ""
264		if cfg.Local != nil {
265			ip = cfg.Local.IP
266		}
267		if ip == "" {
268			ip = lookupIP(ctx, p.Runner, name, DefaultNetwork)
269		}
270		if ip == "" {
271			return fmt.Errorf("no IP for %s: check 'govirt status %s'", name, name)
272		}
273		user := cfg.VM.Users[0].Username
274		sshPath, err := exec.LookPath("ssh")
275		if err != nil {
276			return fmt.Errorf("ssh not found: %w", err)
277		}
278		argv := []string{"ssh", "-o", "StrictHostKeyChecking=no", user + "@" + ip}
279		return syscall.Exec(sshPath, argv, os.Environ())
280	}
281	
282	func (p *Provider) exists(ctx context.Context, name string) bool {
283		return p.domState(ctx, name) != ""
284	}
285	
286	func (p *Provider) domState(ctx context.Context, name string) string {
287		out, err := p.Runner.Output(ctx, "virsh", "dominfo", name)
288		if err != nil {
289			return ""
290		}
291		return parseDominfoState(string(out))
292	}
293	
294	// checkPrereqs verifies the local toolchain and /dev/kvm access.
295	func (p *Provider) checkPrereqs() error {
296		required := map[string]string{
297			"virsh":       "virsh not found: install libvirt (sudo apt install libvirt-daemon-system)",
298			"virt-install": "virt-install not found: install virtinst (sudo apt install virtinst)",
299			"qemu-img":    "qemu-img not found: install qemu-utils (sudo apt install qemu-utils)",
300		}
301		for bin, msg := range required {
302			if _, err := exec.LookPath(bin); err != nil {
303				return fmt.Errorf("%s", msg)
304			}
305		}
306		if detectISOTool() == isoNone {
307			return fmt.Errorf("neither cloud-localds nor genisoimage found: install cloud-image-utils or genisoimage")
308		}
309		if _, err := os.Stat("/dev/kvm"); err != nil {
310			return fmt.Errorf("/dev/kvm not accessible: check that the current user is in the 'kvm' group")
311		}
312		return nil
313	}
314	
315	// detectISOTool returns the preferred available NoCloud ISO generator.
316	func detectISOTool() isoTool {
317		if _, err := exec.LookPath("cloud-localds"); err == nil {
318			return isoCloudLocalds
319		}
320		if _, err := exec.LookPath("genisoimage"); err == nil {
321			return isoGenisoimage
322		}
323		return isoNone
324	}
325	
326	// parseMemoryMB converts a memory string ("2G", "512M", "1024") to megabytes.
327	func parseMemoryMB(mem string) (int, error) {
328		s := strings.TrimSpace(mem)
329		if s == "" {
330			return 0, fmt.Errorf("empty memory value")
331		}
332		mult := 1
333		switch last := s[len(s)-1]; last {
334		case 'G', 'g':
335			mult = 1024
336			s = s[:len(s)-1]
337		case 'M', 'm':
338			mult = 1
339			s = s[:len(s)-1]
340		}
341		n, err := strconv.Atoi(strings.TrimSpace(s))
342		if err != nil {
343			return 0, fmt.Errorf("invalid memory value %q: %w", mem, err)
344		}
345		return n * mult, nil
346	}
347	
348	// mapOSVariant maps an image shorthand to a libvirt os-variant, falling back to
349	// ubuntu20.04 for unknown values.
350	func mapOSVariant(image string) string {
351		switch image {
352		case "24.04":
353			return "ubuntu24.04"
354		case "22.04":
355			return "ubuntu22.04"
356		case "20.04":
357			return "ubuntu20.04"
358		default:
359			return "ubuntu20.04"
360		}
361	}
362	
363	// buildVirtInstallArgs assembles the virt-install argument slice.
364	func buildVirtInstallArgs(name string, memMB, cpus int, disk, iso, variant, network string, mounts []config.Mount, useVirtiofs bool) []string {
365		if cpus <= 0 {
366			cpus = config.DefaultCPUs
367		}
368		args := []string{
369			"--name", name,
370			"--memory", strconv.Itoa(memMB),
371			"--vcpus", strconv.Itoa(cpus),
372			"--disk", "path=" + disk + ",format=qcow2",
373			"--disk", "path=" + iso + ",device=cdrom",
374			"--os-variant", variant,
375			"--network", "network=" + network,
376			"--graphics", "none",
377			"--noautoconsole",
378			"--import",
379		}
380		for _, m := range mounts {
381			tag := cloudinit.MountTag(m.Target)
382			driver := "virtiofs"
383			if !useVirtiofs {
384				driver = "9p"
385			}
386			args = append(args, "--filesystem",
387				fmt.Sprintf("source=%s,target=%s,driver.type=%s", m.Source, tag, driver))
388		}
389		return args
390	}
391	
392	var _ provider.VMProvider = (*Provider)(nil)
