// Package digitalocean implements the DigitalOcean VMProvider backed by the godo
// API client. External API access is funneled through small interfaces wrapping
// only the godo methods this package calls, so unit tests can fake them without
// network access. The API token is read from the environment at runtime and is
// never logged or written to disk.
package digitalocean

import (
	"context"
	"fmt"
	"os"

	"github.com/digitalocean/godo"
)

// TokenEnvVar is the environment variable holding the DigitalOcean API token.
const TokenEnvVar = "DIGITALOCEAN_TOKEN"

// DropletService wraps the godo Droplets methods used by this package.
type DropletService interface {
	Create(ctx context.Context, req *godo.DropletCreateRequest) (*godo.Droplet, *godo.Response, error)
	Get(ctx context.Context, id int) (*godo.Droplet, *godo.Response, error)
	Delete(ctx context.Context, id int) (*godo.Response, error)
	List(ctx context.Context, opt *godo.ListOptions) ([]godo.Droplet, *godo.Response, error)
}

// DropletActionService wraps the godo DropletActions methods used by this package.
type DropletActionService interface {
	Shutdown(ctx context.Context, id int) (*godo.Action, *godo.Response, error)
	PowerOn(ctx context.Context, id int) (*godo.Action, *godo.Response, error)
}

// FirewallService wraps the godo Firewalls methods used by this package.
type FirewallService interface {
	Create(ctx context.Context, req *godo.FirewallRequest) (*godo.Firewall, *godo.Response, error)
	Delete(ctx context.Context, id string) (*godo.Response, error)
}

// DomainService wraps the godo Domains record methods used by this package.
type DomainService interface {
	CreateRecord(ctx context.Context, domain string, req *godo.DomainRecordEditRequest) (*godo.DomainRecord, *godo.Response, error)
	DeleteRecord(ctx context.Context, domain string, id int) (*godo.Response, error)
	EditRecord(ctx context.Context, domain string, id int, req *godo.DomainRecordEditRequest) (*godo.DomainRecord, *godo.Response, error)
}

// API is the aggregate of DigitalOcean services this provider depends on. A real
// implementation adapts *godo.Client; tests supply a fake.
type API interface {
	Droplets() DropletService
	DropletActions() DropletActionService
	Firewalls() FirewallService
	Domains() DomainService
}

// godoAPI adapts a *godo.Client to the API interface. The godo service fields
// already satisfy the wrapping interfaces, since those interfaces are subsets of
// the godo service interfaces.
type godoAPI struct {
	client *godo.Client
}

func (a godoAPI) Droplets() DropletService             { return a.client.Droplets }
func (a godoAPI) DropletActions() DropletActionService { return a.client.DropletActions }
func (a godoAPI) Firewalls() FirewallService           { return a.client.Firewalls }
func (a godoAPI) Domains() DomainService               { return a.client.Domains }

// newAPIFromEnv builds an API backed by a real godo client authenticated with
// the DIGITALOCEAN_TOKEN environment variable. The token is read at call time
// and never persisted or logged.
func newAPIFromEnv() (API, error) {
	token := os.Getenv(TokenEnvVar)
	if token == "" {
		return nil, fmt.Errorf("DIGITALOCEAN_TOKEN not set: export DIGITALOCEAN_TOKEN=<your-token>")
	}
	// godo.NewFromToken configures an oauth2 transport that sends the token over
	// HTTPS to the DigitalOcean API; it is never written to disk.
	return godoAPI{client: godo.NewFromToken(token)}, nil
}

package digitalocean

import (
	"context"
	"fmt"
	"time"

	"github.com/digitalocean/godo"
	"github.com/gherlein/govirt/internal/config"
)

// dropletPoll controls how long Create waits for a droplet to become active with
// an assigned public IP.
type pollConfig struct {
	interval time.Duration
	timeout  time.Duration
}

var defaultDropletPoll = pollConfig{interval: 5 * time.Second, timeout: 5 * time.Minute}

// buildDropletRequest maps the VM config and processed cloud-init document to a
// godo droplet create request. SSH keys are delivered via cloud-init UserData,
// not the godo SSHKeys field.
func buildDropletRequest(cfg *config.Config, userData string) *godo.DropletCreateRequest {
	vm := cfg.VM
	return &godo.DropletCreateRequest{
		Name:   vm.Name,
		Region: vm.DORegion,
		Size:   vm.DOSize,
		Image:  godo.DropletCreateImage{Slug: vm.DOImage},
		// A public IP is required for SSH and DNS, so request public networking.
		IPv6:     false,
		UserData: userData,
		VPCUUID:  vm.DOVpcID,
		Tags:     []string{"govirt"},
	}
}

// createDroplet creates the droplet and polls until it is active with a public
// IP. It returns the droplet id and public IP.
func (p *Provider) createDroplet(ctx context.Context, cfg *config.Config, userData string) (int, string, error) {
	req := buildDropletRequest(cfg, userData)
	created, _, err := p.api.Droplets().Create(ctx, req)
	if err != nil {
		return 0, "", fmt.Errorf("creating droplet: %w", err)
	}
	id := created.ID

	ip, err := p.waitForActiveIP(ctx, id, p.poll)
	if err != nil {
		return id, "", err
	}
	return id, ip, nil
}

// waitForActiveIP polls the droplet until it reports status "active" and has a
// public IPv4 address assigned.
func (p *Provider) waitForActiveIP(ctx context.Context, id int, poll pollConfig) (string, error) {
	deadline := time.Now().Add(poll.timeout)
	for {
		droplet, _, err := p.api.Droplets().Get(ctx, id)
		if err != nil {
			return "", fmt.Errorf("polling droplet %d: %w", id, err)
		}
		if droplet.Status == "active" {
			ip, err := droplet.PublicIPv4()
			if err == nil && ip != "" {
				return ip, nil
			}
		}
		if time.Now().After(deadline) {
			return "", fmt.Errorf("droplet %d not active with public IP after %s", id, poll.timeout)
		}
		select {
		case <-ctx.Done():
			return "", ctx.Err()
		case <-time.After(poll.interval):
		}
	}
}

package digitalocean

import (
	"context"
	"fmt"

	"github.com/digitalocean/godo"
	"github.com/gherlein/govirt/internal/config"
)

// DefaultCIDR is the firewall source used when ssh_cidr/web_cidr are unset.
const DefaultCIDR = "0.0.0.0/0"

// buildFirewallRequest builds a firewall allowing inbound TCP on 22 (SSH), 80
// and 443 (web), attached to the given droplet. SSH uses ssh_cidr; HTTP/HTTPS
// use web_cidr; both default to 0.0.0.0/0 when unset.
func buildFirewallRequest(cfg *config.Config, dropletID int) *godo.FirewallRequest {
	sshCIDR := cfg.VM.SSHCidr
	if sshCIDR == "" {
		sshCIDR = DefaultCIDR
	}
	webCIDR := cfg.VM.WebCidr
	if webCIDR == "" {
		webCIDR = DefaultCIDR
	}
	inbound := func(port, cidr string) godo.InboundRule {
		return godo.InboundRule{
			Protocol:  "tcp",
			PortRange: port,
			Sources:   &godo.Sources{Addresses: []string{cidr}},
		}
	}
	return &godo.FirewallRequest{
		Name: "govirt-" + cfg.VM.Name,
		InboundRules: []godo.InboundRule{
			inbound("22", sshCIDR),
			inbound("80", webCIDR),
			inbound("443", webCIDR),
		},
		DropletIDs: []int{dropletID},
	}
}

// createFirewall creates and attaches the firewall, returning its id.
func (p *Provider) createFirewall(ctx context.Context, cfg *config.Config, dropletID int) (string, error) {
	req := buildFirewallRequest(cfg, dropletID)
	fw, _, err := p.api.Firewalls().Create(ctx, req)
	if err != nil {
		return "", fmt.Errorf("creating firewall: %w", err)
	}
	return fw.ID, nil
}

package digitalocean

import (
	"context"
	"fmt"

	"github.com/digitalocean/godo"
	"github.com/gherlein/govirt/internal/config"
)

// buildARecord builds a request for an A record named name pointing at ip.
func buildARecord(name, ip string, ttl int) *godo.DomainRecordEditRequest {
	return &godo.DomainRecordEditRequest{
		Type: "A",
		Name: name,
		Data: ip,
		TTL:  ttl,
	}
}

// buildCNAMERecord builds a request for a CNAME record named alias pointing at
// target. DigitalOcean requires CNAME data to be a fully qualified name ending
// in a dot.
func buildCNAMERecord(alias, target string, ttl int) *godo.DomainRecordEditRequest {
	if len(target) == 0 || target[len(target)-1] != '.' {
		target += "."
	}
	return &godo.DomainRecordEditRequest{
		Type: "CNAME",
		Name: alias,
		Data: target,
		TTL:  ttl,
	}
}

// planDNSRecords returns the ordered set of record-edit requests to create for
// the given config and droplet IP: the hostname A record, an optional apex A
// record, and one CNAME per alias pointing at the hostname FQDN. The DNS section
// being nil yields no records.
func planDNSRecords(cfg *config.Config, ip string) []*godo.DomainRecordEditRequest {
	if cfg.DNS == nil {
		return nil
	}
	dns := cfg.DNS
	ttl := dns.TTL
	hostnameFQDN := dns.Hostname + "." + dns.Domain
	var records []*godo.DomainRecordEditRequest
	records = append(records, buildARecord(dns.Hostname, ip, ttl))
	if dns.IsApexDomain {
		records = append(records, buildARecord("@", ip, ttl))
	}
	for _, alias := range dns.CNAMEAliases {
		records = append(records, buildCNAMERecord(alias, hostnameFQDN, ttl))
	}
	return records
}

// createDNSRecords creates all planned DNS records in cfg.DNS.Domain and returns
// the tracked DORecords (with their DigitalOcean numeric IDs).
func (p *Provider) createDNSRecords(ctx context.Context, cfg *config.Config, ip string) ([]config.DORecord, error) {
	plan := planDNSRecords(cfg, ip)
	if len(plan) == 0 {
		return nil, nil
	}
	domain := cfg.DNS.Domain
	var tracked []config.DORecord
	for _, req := range plan {
		rec, _, err := p.api.Domains().CreateRecord(ctx, domain, req)
		if err != nil {
			return tracked, fmt.Errorf("creating %s record %q: %w", req.Type, req.Name, err)
		}
		tracked = append(tracked, config.DORecord{ID: rec.ID, Name: req.Name, Type: req.Type})
	}
	return tracked, nil
}

// deleteDNSRecords deletes every tracked DNS record. It continues past
// individual failures and returns the first error encountered.
func (p *Provider) deleteDNSRecords(ctx context.Context, cfg *config.Config) error {
	if cfg.DO == nil || cfg.DNS == nil {
		return nil
	}
	domain := cfg.DNS.Domain
	var firstErr error
	for _, rec := range cfg.DO.DNSRecords {
		if _, err := p.api.Domains().DeleteRecord(ctx, domain, rec.ID); err != nil && firstErr == nil {
			firstErr = fmt.Errorf("deleting %s record %q: %w", rec.Type, rec.Name, err)
		}
	}
	cfg.DO.DNSRecords = nil
	return firstErr
}

// SwapDNS updates every tracked A record to the droplet's current public IP and
// re-creates the configured CNAME aliases. It implements provider.DNSSwapper.
func (p *Provider) SwapDNS(ctx context.Context, cfg *config.Config) error {
	if cfg.DO == nil {
		return fmt.Errorf("no DigitalOcean state for %s: nothing to swap", cfg.VM.Name)
	}
	if cfg.DNS == nil {
		return fmt.Errorf("no dns section for %s: nothing to swap", cfg.VM.Name)
	}
	droplet, _, err := p.api.Droplets().Get(ctx, cfg.DO.DropletID)
	if err != nil {
		return fmt.Errorf("getting droplet %d: %w", cfg.DO.DropletID, err)
	}
	ip, err := droplet.PublicIPv4()
	if err != nil || ip == "" {
		return fmt.Errorf("droplet %d has no public IP", cfg.DO.DropletID)
	}

	domain := cfg.DNS.Domain
	ttl := cfg.DNS.TTL
	hostnameFQDN := cfg.DNS.Hostname + "." + cfg.DNS.Domain

	var updated []config.DORecord
	for _, rec := range cfg.DO.DNSRecords {
		switch rec.Type {
		case "A":
			req := buildARecord(rec.Name, ip, ttl)
			if _, _, err := p.api.Domains().EditRecord(ctx, domain, rec.ID, req); err != nil {
				return fmt.Errorf("updating A record %q: %w", rec.Name, err)
			}
			updated = append(updated, rec)
		case "CNAME":
			// Re-create CNAME aliases so they re-point at the current hostname FQDN.
			if _, err := p.api.Domains().DeleteRecord(ctx, domain, rec.ID); err != nil {
				return fmt.Errorf("removing stale CNAME %q: %w", rec.Name, err)
			}
			req := buildCNAMERecord(rec.Name, hostnameFQDN, ttl)
			newRec, _, err := p.api.Domains().CreateRecord(ctx, domain, req)
			if err != nil {
				return fmt.Errorf("re-creating CNAME %q: %w", rec.Name, err)
			}
			updated = append(updated, config.DORecord{ID: newRec.ID, Name: rec.Name, Type: "CNAME"})
		default:
			updated = append(updated, rec)
		}
	}
	cfg.DO.DNSRecords = updated
	cfg.DO.PublicIP = ip
	return nil
}

package digitalocean

import (
	"context"
	"fmt"
	"io"
	"os"
	"os/exec"
	"syscall"

	"github.com/gherlein/govirt/internal/config"
	"github.com/gherlein/govirt/internal/provider"
)

// Provider is the DigitalOcean VMProvider implementation. The API is resolved
// lazily from the DIGITALOCEAN_TOKEN environment variable on first use so that
// constructing a Provider never requires a token; tests inject a fake API
// directly.
type Provider struct {
	api  API
	poll pollConfig
	Out  io.Writer
}

// New returns a Provider with production defaults. The DigitalOcean API client
// is built lazily on first use from the DIGITALOCEAN_TOKEN environment variable.
func New() *Provider {
	return &Provider{
		poll: defaultDropletPoll,
		Out:  os.Stderr,
	}
}

// Name implements provider.VMProvider.
func (p *Provider) Name() string { return "do" }

// ensureAPI lazily builds the godo-backed API from the environment if one has
// not been injected.
func (p *Provider) ensureAPI() error {
	if p.api != nil {
		return nil
	}
	api, err := newAPIFromEnv()
	if err != nil {
		return err
	}
	p.api = api
	return nil
}

// Create provisions a droplet, attaches a firewall, creates DNS records, and
// records the result in cfg.DO. The processed cloud-init document at
// cloudInitPath is passed as the droplet UserData.
func (p *Provider) Create(ctx context.Context, cfg *config.Config, cloudInitPath string) error {
	if cfg.VM == nil {
		return fmt.Errorf("config missing vm section")
	}
	if err := config.ValidateName(cfg.VM.Name); err != nil {
		return err
	}
	if err := p.ensureAPI(); err != nil {
		return err
	}

	userData, err := os.ReadFile(cloudInitPath)
	if err != nil {
		return fmt.Errorf("reading processed cloud-init: %w", err)
	}

	dropletID, ip, err := p.createDroplet(ctx, cfg, string(userData))
	if err != nil {
		return err
	}

	firewallID, err := p.createFirewall(ctx, cfg, dropletID)
	if err != nil {
		return err
	}

	records, err := p.createDNSRecords(ctx, cfg, ip)
	if err != nil {
		return err
	}

	cfg.DO = &config.DOState{
		DropletID:  dropletID,
		PublicIP:   ip,
		FirewallID: firewallID,
		DNSRecords: records,
	}
	if cfg.DNS != nil {
		cfg.DO.FQDN = cfg.DNS.Hostname + "." + cfg.DNS.Domain
	}
	return nil
}

// Delete removes DNS records, the firewall, and the droplet, then clears cfg.DO.
func (p *Provider) Delete(ctx context.Context, cfg *config.Config) error {
	if cfg.DO == nil {
		return nil
	}
	if err := p.ensureAPI(); err != nil {
		return err
	}

	if err := p.deleteDNSRecords(ctx, cfg); err != nil {
		return err
	}
	if cfg.DO.FirewallID != "" {
		if _, err := p.api.Firewalls().Delete(ctx, cfg.DO.FirewallID); err != nil {
			return fmt.Errorf("deleting firewall %s: %w", cfg.DO.FirewallID, err)
		}
	}
	if cfg.DO.DropletID != 0 {
		if _, err := p.api.Droplets().Delete(ctx, cfg.DO.DropletID); err != nil {
			return fmt.Errorf("deleting droplet %d: %w", cfg.DO.DropletID, err)
		}
	}
	cfg.DO = nil
	return nil
}

// Status reports the droplet state and current public IP.
func (p *Provider) Status(ctx context.Context, cfg *config.Config) (*provider.VMStatus, error) {
	if cfg.DO == nil || cfg.DO.DropletID == 0 {
		return nil, fmt.Errorf("VM not found: check 'govirt list --do' for available VMs")
	}
	if err := p.ensureAPI(); err != nil {
		return nil, err
	}
	droplet, _, err := p.api.Droplets().Get(ctx, cfg.DO.DropletID)
	if err != nil {
		return nil, fmt.Errorf("getting droplet %d: %w", cfg.DO.DropletID, err)
	}
	ip, _ := droplet.PublicIPv4()
	return &provider.VMStatus{
		Name:     droplet.Name,
		State:    droplet.Status,
		IP:       ip,
		Provider: p.Name(),
	}, nil
}

// List returns all droplets visible to the account.
func (p *Provider) List(ctx context.Context) ([]provider.VMStatus, error) {
	if err := p.ensureAPI(); err != nil {
		return nil, err
	}
	droplets, _, err := p.api.Droplets().List(ctx, nil)
	if err != nil {
		return nil, fmt.Errorf("listing droplets: %w", err)
	}
	var result []provider.VMStatus
	for i := range droplets {
		d := &droplets[i]
		ip, _ := d.PublicIPv4()
		result = append(result, provider.VMStatus{
			Name:     d.Name,
			State:    d.Status,
			IP:       ip,
			Provider: p.Name(),
		})
	}
	return result, nil
}

// Stop performs a graceful droplet shutdown.
func (p *Provider) Stop(ctx context.Context, cfg *config.Config) error {
	if cfg.DO == nil || cfg.DO.DropletID == 0 {
		return fmt.Errorf("VM not found: check 'govirt list --do' for available VMs")
	}
	if err := p.ensureAPI(); err != nil {
		return err
	}
	if _, _, err := p.api.DropletActions().Shutdown(ctx, cfg.DO.DropletID); err != nil {
		return fmt.Errorf("shutting down droplet %d: %w", cfg.DO.DropletID, err)
	}
	return nil
}

// Start powers the droplet on.
func (p *Provider) Start(ctx context.Context, cfg *config.Config) error {
	if cfg.DO == nil || cfg.DO.DropletID == 0 {
		return fmt.Errorf("VM not found: check 'govirt list --do' for available VMs")
	}
	if err := p.ensureAPI(); err != nil {
		return err
	}
	if _, _, err := p.api.DropletActions().PowerOn(ctx, cfg.DO.DropletID); err != nil {
		return fmt.Errorf("powering on droplet %d: %w", cfg.DO.DropletID, err)
	}
	return nil
}

// SSH replaces the current process with an interactive ssh session to the
// droplet's public IP, using the first configured user.
func (p *Provider) SSH(ctx context.Context, cfg *config.Config) error {
	if cfg.VM == nil || len(cfg.VM.Users) == 0 {
		return fmt.Errorf("no users defined")
	}
	if cfg.DO == nil || cfg.DO.PublicIP == "" {
		return fmt.Errorf("no IP for %s: check 'govirt status %s --do'", cfg.VM.Name, cfg.VM.Name)
	}
	user := cfg.VM.Users[0].Username
	sshPath, err := exec.LookPath("ssh")
	if err != nil {
		return fmt.Errorf("ssh not found: %w", err)
	}
	argv := []string{"ssh", "-o", "StrictHostKeyChecking=no", user + "@" + cfg.DO.PublicIP}
	return syscall.Exec(sshPath, argv, os.Environ())
}

