// fakeDroplets records create/get/delete/list calls and returns scripted values.
type fakeDroplets struct {
	created      *godo.DropletCreateRequest
	createResult *godo.Droplet
	getResults   []*godo.Droplet
	getCalls     int
	deleted      []int
	listResult   []godo.Droplet
	err          error
}

func (f *fakeDroplets) Create(ctx context.Context, req *godo.DropletCreateRequest) (*godo.Droplet, *godo.Response, error) {
	f.created = req
	if f.err != nil {
		return nil, nil, f.err
	}
	return f.createResult, nil, nil
}

func (f *fakeDroplets) Get(ctx context.Context, id int) (*godo.Droplet, *godo.Response, error) {
	if f.err != nil {
		return nil, nil, f.err
	}
	i := f.getCalls
	if i >= len(f.getResults) {
		i = len(f.getResults) - 1
	}
	f.getCalls++
	return f.getResults[i], nil, nil
}

func (f *fakeDroplets) Delete(ctx context.Context, id int) (*godo.Response, error) {
	f.deleted = append(f.deleted, id)
	return nil, f.err
}

func (f *fakeDroplets) List(ctx context.Context, opt *godo.ListOptions) ([]godo.Droplet, *godo.Response, error) {
	return f.listResult, nil, f.err
}

type fakeActions struct {
	shutdownID int
	powerOnID  int
	err        error
}

func (f *fakeActions) Shutdown(ctx context.Context, id int) (*godo.Action, *godo.Response, error) {
	f.shutdownID = id
	return nil, nil, f.err
}

func (f *fakeActions) PowerOn(ctx context.Context, id int) (*godo.Action, *godo.Response, error) {
	f.powerOnID = id
	return nil, nil, f.err
}

type fakeFirewalls struct {
	created *godo.FirewallRequest
	result  *godo.Firewall
	deleted []string
	err     error
}

func (f *fakeFirewalls) Create(ctx context.Context, req *godo.FirewallRequest) (*godo.Firewall, *godo.Response, error) {
	f.created = req
	if f.err != nil {
		return nil, nil, f.err
	}
	return f.result, nil, nil
}

func (f *fakeFirewalls) Delete(ctx context.Context, id string) (*godo.Response, error) {
	f.deleted = append(f.deleted, id)
	return nil, f.err
}

type createdRecord struct {
	domain string
	req    *godo.DomainRecordEditRequest
}

type editedRecord struct {
	domain string
	id     int
	req    *godo.DomainRecordEditRequest
}

type fakeDomains struct {
	created     []createdRecord
	edited      []editedRecord
	deleted     []int
	nextID      int
	createErr   error
	deleteErr   error
	editErr     error
}

func (f *fakeDomains) CreateRecord(ctx context.Context, domain string, req *godo.DomainRecordEditRequest) (*godo.DomainRecord, *godo.Response, error) {
	if f.createErr != nil {
		return nil, nil, f.createErr
	}
	f.nextID++
	f.created = append(f.created, createdRecord{domain: domain, req: req})
	return &godo.DomainRecord{ID: f.nextID, Type: req.Type, Name: req.Name, Data: req.Data}, nil, nil
}

func (f *fakeDomains) DeleteRecord(ctx context.Context, domain string, id int) (*godo.Response, error) {
	f.deleted = append(f.deleted, id)
	return nil, f.deleteErr
}

func (f *fakeDomains) EditRecord(ctx context.Context, domain string, id int, req *godo.DomainRecordEditRequest) (*godo.DomainRecord, *godo.Response, error) {
	if f.editErr != nil {
		return nil, nil, f.editErr
	}
	f.edited = append(f.edited, editedRecord{domain: domain, id: id, req: req})
	return &godo.DomainRecord{ID: id, Type: req.Type, Name: req.Name, Data: req.Data}, nil, nil
}

// fakeAPI aggregates the fakes into the API interface.
type fakeAPI struct {
	droplets  *fakeDroplets
	actions   *fakeActions
	firewalls *fakeFirewalls
	domains   *fakeDomains
}

func (f *fakeAPI) Droplets() DropletService             { return f.droplets }
