func (f *fakeAPI) Firewalls() FirewallService           { return f.firewalls }
func (f *fakeAPI) Domains() DomainService               { return f.domains }

func newFakeAPI() *fakeAPI {
	return &fakeAPI{
		droplets:  &fakeDroplets{},
		actions:   &fakeActions{},
		firewalls: &fakeFirewalls{},
		domains:   &fakeDomains{},
	}
}

