func TestBuildDropletRequest(t *testing.T) {
	tests := []struct {
		name     string
		mutate   func(*config.Config)
		userData string
		want     godo.DropletCreateRequest
	}{
		{
			name:     "basic mapping",
			userData: "#cloud-config\n",
			want: godo.DropletCreateRequest{
				Name:     "web",
				Region:   "nyc3",
				Size:     "s-2vcpu-4gb",
				Image:    godo.DropletCreateImage{Slug: "ubuntu-24-04-x64"},
				UserData: "#cloud-config\n",
				Tags:     []string{"govirt"},
			},
		},
		{
			name: "vpc set",
			mutate: func(c *config.Config) {
				c.VM.DOVpcID = "vpc-uuid-123"
			},
			userData: "data",
			want: godo.DropletCreateRequest{
				Name:     "web",
				Region:   "nyc3",
				Size:     "s-2vcpu-4gb",
				Image:    godo.DropletCreateImage{Slug: "ubuntu-24-04-x64"},
				UserData: "data",
				VPCUUID:  "vpc-uuid-123",
				Tags:     []string{"govirt"},
			},
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			cfg := baseConfig()
			if tt.mutate != nil {
				tt.mutate(cfg)
			}
			got := buildDropletRequest(cfg, tt.userData)
			if got.Name != tt.want.Name || got.Region != tt.want.Region ||
				got.Size != tt.want.Size || got.Image.Slug != tt.want.Image.Slug ||
				got.UserData != tt.want.UserData || got.VPCUUID != tt.want.VPCUUID {
				t.Errorf("buildDropletRequest() = %+v, want %+v", got, tt.want)
			}
			if len(got.Tags) != 1 || got.Tags[0] != "govirt" {
				t.Errorf("Tags = %v, want [govirt]", got.Tags)
			}
		})
	}
}

func TestBuildFirewallRequest(t *testing.T) {
	tests := []struct {
		name        string
		sshCIDR     string
		webCIDR     string
		wantSSHSrc  string
		wantWebSrc  string
	}{
		{name: "defaults", sshCIDR: "", webCIDR: "", wantSSHSrc: DefaultCIDR, wantWebSrc: DefaultCIDR},
		{name: "custom cidrs", sshCIDR: "10.0.0.0/8", webCIDR: "192.168.0.0/16", wantSSHSrc: "10.0.0.0/8", wantWebSrc: "192.168.0.0/16"},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			cfg := baseConfig()
			cfg.VM.SSHCidr = tt.sshCIDR
			cfg.VM.WebCidr = tt.webCIDR
			got := buildFirewallRequest(cfg, 42)

			if got.Name != "govirt-web" {
				t.Errorf("Name = %q, want govirt-web", got.Name)
			}
			if len(got.DropletIDs) != 1 || got.DropletIDs[0] != 42 {
				t.Errorf("DropletIDs = %v, want [42]", got.DropletIDs)
			}
			if len(got.InboundRules) != 3 {
				t.Fatalf("got %d inbound rules, want 3", len(got.InboundRules))
			}
			wantPorts := map[string]string{"22": tt.wantSSHSrc, "80": tt.wantWebSrc, "443": tt.wantWebSrc}
			for _, rule := range got.InboundRules {
				if rule.Protocol != "tcp" {
					t.Errorf("port %s protocol = %q, want tcp", rule.PortRange, rule.Protocol)
				}
				wantSrc, ok := wantPorts[rule.PortRange]
				if !ok {
					t.Errorf("unexpected port %q", rule.PortRange)
					continue
				}
				if rule.Sources == nil || len(rule.Sources.Addresses) != 1 || rule.Sources.Addresses[0] != wantSrc {
					t.Errorf("port %s sources = %+v, want %q", rule.PortRange, rule.Sources, wantSrc)
				}
				delete(wantPorts, rule.PortRange)
			}
			if len(wantPorts) != 0 {
				t.Errorf("missing ports: %v", wantPorts)
			}
		})
	}
}

func TestPlanDNSRecords(t *testing.T) {
	tests := []struct {
		name string
		dns  *config.DNSConfig
		want []godo.DomainRecordEditRequest
	}{
		{name: "nil dns yields none", dns: nil, want: nil},
		{
			name: "hostname A only",
			dns:  &config.DNSConfig{Hostname: "web", Domain: "example.com", TTL: 300},
			want: []godo.DomainRecordEditRequest{
				{Type: "A", Name: "web", Data: "1.2.3.4", TTL: 300},
			},
		},
		{
			name: "apex adds @ record",
			dns:  &config.DNSConfig{Hostname: "web", Domain: "example.com", TTL: 300, IsApexDomain: true},
			want: []godo.DomainRecordEditRequest{
				{Type: "A", Name: "web", Data: "1.2.3.4", TTL: 300},
				{Type: "A", Name: "@", Data: "1.2.3.4", TTL: 300},
			},
		},
		{
			name: "cname aliases point at hostname fqdn",
			dns:  &config.DNSConfig{Hostname: "web", Domain: "example.com", TTL: 300, CNAMEAliases: []string{"www"}},
			want: []godo.DomainRecordEditRequest{
				{Type: "A", Name: "web", Data: "1.2.3.4", TTL: 300},
				{Type: "CNAME", Name: "www", Data: "web.example.com.", TTL: 300},
			},
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			cfg := baseConfig()
			cfg.DNS = tt.dns
			got := planDNSRecords(cfg, "1.2.3.4")
			if len(got) != len(tt.want) {
				t.Fatalf("got %d records, want %d", len(got), len(tt.want))
			}
			for i, w := range tt.want {
				g := got[i]
				if g.Type != w.Type || g.Name != w.Name || g.Data != w.Data || g.TTL != w.TTL {
					t.Errorf("record[%d] = %+v, want %+v", i, *g, w)
				}
			}
		})
	}
}

