func TestSwapDNS(t *testing.T) {
	api := newFakeAPI()
	api.droplets.getResults = []*godo.Droplet{activeDroplet(100, "8.8.8.8")}
	cfg := baseConfig()
	cfg.DNS = &config.DNSConfig{Hostname: "web", Domain: "example.com", TTL: 300}
	cfg.DO = &config.DOState{
		DropletID: 100,
		PublicIP:  "1.1.1.1",
		DNSRecords: []config.DORecord{
			{ID: 5, Name: "web", Type: "A"},
			{ID: 6, Name: "www", Type: "CNAME"},
		},
	}
	p := &Provider{api: api}

	if err := p.SwapDNS(context.Background(), cfg); err != nil {
		t.Fatal(err)
	}
	if cfg.DO.PublicIP != "8.8.8.8" {
		t.Errorf("PublicIP = %q, want 8.8.8.8", cfg.DO.PublicIP)
	}
	// A record edited to new IP.
	if len(api.domains.edited) != 1 || api.domains.edited[0].id != 5 || api.domains.edited[0].req.Data != "8.8.8.8" {
		t.Errorf("edited = %+v, want A record 5 -> 8.8.8.8", api.domains.edited)
	}
	// CNAME deleted then re-created.
	if len(api.domains.deleted) != 1 || api.domains.deleted[0] != 6 {
		t.Errorf("deleted = %v, want [6]", api.domains.deleted)
	}
	if len(api.domains.created) != 1 || api.domains.created[0].req.Type != "CNAME" {
		t.Errorf("created = %+v, want one CNAME", api.domains.created)
	}
}

